function validatePorts(ports) {
    const exposedPorts = {};
    const conflicts = [];

    for (let i = 0; i < ports.length; i++) {
        const service = ports[i];
        const port = service.ports[0];
        const exposedPort = service.exposedPorts[0];

        if (exposedPort in exposedPorts) {
            conflicts.push([service.name, port]);
        }
        exposedPorts[exposedPort] = true;
    }

    return conflicts;
}

